        gameObject.transform.position = new Vector3(trigger_pos.x, trigger_pos.y + 0.4f, trigger_pos.z);
        gameObject.transform.rotation = new Quaternion(0, 0, 0, 0);
        rb.constraints = RigidbodyConstraints.FreezeAll;
        isSnapped = true;
    }
}
